	for i, src := range paths {
		name := strings.TrimSpace(files[i].Name)
		if name == "" {
			name = fmt.Sprintf("output-%d", i+1)
		}
		if !strings.HasSuffix(strings.ToLower(name), ".pdf") {
			name += ".pdf"
		}
		if err := copyFile(src, filepath.Join(files[i].OutDir, name)); err != nil {
			return err
		}
	}
	return nil
}

