		t.Fatal(err)
	}

	for _, name := range []string{"output-1.pdf", "output-2.pdf"} {
		if _, err := os.Stat(filepath.Join(outDir, name)); err != nil {
			t.Errorf("expected %s: %v", name, err)
		}
	}
}

