			t.Fatal(err)
		}

		data, _ := os.ReadFile(out)
		if bytes.Contains(data, []byte("A2")) {
			// Find context around "A2"
			idx := bytes.Index(data, []byte("A2"))
			start := max(0, idx-20)
			end := min(len(data), idx+20)
			t.Errorf("iter %d: A2 found at offset %d, context: %q", i, idx, data[start:end])
